import { TaskStatus } from '../types/task';

/**
 * Defines the valid state transitions for a task.
 * Keys are current statuses, values are arrays of statuses that can be transitioned to.
 */
const VALID_TASK_TRANSITIONS: Readonly<Record<TaskStatus, TaskStatus[]>> = {
  [TaskStatus.Todo]: [TaskStatus.InProgress],
  [TaskStatus.InProgress]: [TaskStatus.Todo, TaskStatus.Done],
  [TaskStatus.Done]: [], // Once done, a task cannot transition to any other state.
};

/**
 * Checks if a transition from a current status to a new status is valid.
 * @param currentStatus The current status of the task.
 * @param newStatus The desired new status for the task.
 * @returns True if the transition is valid, false otherwise.
 */
export function isValidTaskTransition(currentStatus: TaskStatus, newStatus: TaskStatus): boolean {
  if (currentStatus === newStatus) {
    return true; // Self-transitions are always valid (no actual change, but not an "illegal" transition)
  }
  const allowedTransitions = VALID_TASK_TRANSITIONS[currentStatus];
  return allowedTransitions ? allowedTransitions.includes(newStatus) : false;
}
