```aether:src/data/tasks.ts
import { Task, TaskStatus } from '../types/task';

// A simple in-memory data store for demonstration purposes
const tasks: Map<string, Task> = new Map();

// Seed some initial data
tasks.set('task-1', { id: 'task-1', title: 'Buy groceries', status: TaskStatus.Todo });
tasks.set('task-2', { id: 'task-2', title: 'Finish report', status: TaskStatus.InProgress });
tasks.set('task-3', { id: 'task-3', title: 'Schedule meeting', status: TaskStatus.Done });

/**
 * Retrieves a task by its ID.
 * @param id The ID of the task to retrieve.
 * @returns The Task object if found, otherwise undefined.
 */
export function getTaskById(id: string): Task | undefined {
  return tasks.get(id);
}

/**
 * Updates the status of a task.
 * @param id The ID of the task to update.
 * @param newStatus The new status for the task.
 * @returns The updated Task object if successful, otherwise undefined (if task not found).
 */
export function updateTaskStatus(id: string, newStatus: TaskStatus): Task | undefined {
  const task = tasks.get(id);
  if (task) {
    task.status = newStatus;
    tasks.set(id, task); // Ensure the map is updated with the modified object
    return { ...task }; // Return a clone to prevent external modification of the stored object
  }
  return undefined;
}

/**
 * Retrieves all tasks.
 * @returns An array of all tasks.
 */
export function getAllTasks(): Task[] {
  return Array.from(tasks.values());
}
