```aether:src/routes/update-task-status.ts
import { TaskStatus } from '../types/task';
import { getTaskById, updateTaskStatus } from '../data/tasks';
import { isValidTaskTransition } from '../utils/task-transitions';
import { TaskTransitionError } from '../errors/task-transition-error';

// Define a simple response structure for the route handler
interface ApiResponse<T> {
  success: boolean;
  data?: T;
  error?: string;
  statusCode: number;
}

/**
 * Handles the request to update a task's status.
 * This function simulates a route handler, taking parameters typically extracted from a request.
 *
 * @param taskId The ID of the task to update.
 * @param newStatus The desired new status for the task.
 * @returns An ApiResponse object indicating success or failure.
 */
export async function updateTaskStatusRouteHandler(
  taskId: string,
  newStatus: TaskStatus
): Promise<ApiResponse<TaskStatus>> {
  try {
    const task = getTaskById(taskId);

    if (!task) {
      return {
        success: false,
        error: `Task with ID '${taskId}' not found.`,
        statusCode: 404,
      };
    }

    if (!Object.values(TaskStatus).includes(newStatus)) {
      return {
        success: false,
        error: `Invalid status value provided: '${newStatus}'. Must be one of: ${Object.values(TaskStatus).join(', ')}.`,
        statusCode: 400,
      };
    }

    if (!isValidTaskTransition(task.status, newStatus)) {
      throw new TaskTransitionError(task.status, newStatus);
    }

    const updatedTask = updateTaskStatus(taskId, newStatus);

    if (!updatedTask) {
      // This case should ideally not be reached if getTaskById succeeded,
      // but it's a good defensive check.
      return {
        success: false,
        error: `Failed to update task with ID '${taskId}'.`,
        statusCode: 500,
      };
    }

    return {
      success: true,
      data: updatedTask.status,
      statusCode: 200,
    };
  } catch (error) {
    if (error instanceof TaskTransitionError) {
      return {
        success: false,
        error: error.message,
        statusCode: 400, // Bad Request for illegal transition
      };
    }
    console.error('Error updating task status:', error);
    return {
      success: false,
      error: 'An unexpected error occurred.',
      statusCode: 500,
    };
  }
}
