import { getAllTasks } from './data/tasks';
import { updateTaskStatusRouteHandler } from './routes/update-task-status';

async function main() {
  console.log('--- Initial Tasks ---');
  console.log(getAllTasks());
  console.log('\n');

  // --- Valid Transitions ---

  console.log('--- Attempting Valid Transitions ---');

  // task-1: todo -> in_progress
  console.log('Updating task-1 (todo -> in_progress)...');
  let response = await updateTaskStatusRouteHandler('task-1', TaskStatus.InProgress);
  console.log(response); // Expected: success, status: in_progress

  // task-2: in_progress -> done
  console.log('Updating task-2 (in_progress -> done)...');
  response = await updateTaskStatusRouteHandler('task-2', TaskStatus.Done);
  console.log(response); // Expected: success, status: done

  // task-1: in_progress -> done
  console.log('Updating task-1 (in_progress -> done)...');
  response = await updateTaskStatusRouteHandler('task-1', TaskStatus.Done);
  console.log(response); // Expected: success, status: done

  console.log('\n--- Tasks After Valid Transitions ---');
  console.log(getAllTasks());
  console.log('\n');

  // --- Invalid Transitions ---

  console.log('--- Attempting Invalid Transitions ---');

  // task-3: done -> todo (illegal)
  console.log('Updating task-3 (done -> todo)...');
  response = await updateTaskStatusRouteHandler('task-3', TaskStatus.Todo);
  console.log(response); // Expected: error, statusCode: 400

  // task-1: done -> in_progress (illegal)
  console.log('Updating task-1 (done -> in_progress)...');
  response = await updateTaskStatusRouteHandler('task-1', TaskStatus.InProgress);
  console.log(response); // Expected: error, statusCode: 400

  // --- Edge Cases ---

  // Non-existent task
  console.log('Updating non-existent task (task-99 -> done)...');
  response = await updateTaskStatusRouteHandler('task-99', TaskStatus.Done);
  console.log(response); // Expected: error, statusCode: 404

  // Invalid status string
  console.log('Updating task-1 with invalid status string...');
  response = await updateTaskStatusRouteHandler('task-1', 'invalid_status' as TaskStatus);
  console.log(response); // Expected: error, statusCode: 400

  // Self-transition (valid, no actual change)
  console.log('Updating task-2 (done -> done)...');
  response = await updateTaskStatusRouteHandler('task-2', TaskStatus.Done);
  console.log(response); // Expected: success, status: done

  console.log('\n--- Final Tasks ---');
  console.log(getAllTasks());
}

main();
